import React, { useState, useEffect } from 'react';
import { View, Text, TouchableOpacity, Alert } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import * as SecureStore from 'expo-secure-store';
import * as WebBrowser from 'expo-web-browser';
import * as AuthSession from 'expo-auth-session';

const OAuthClient = () => {
  const [accessToken, setAccessToken] = useState(null);
  const [refreshToken, setRefreshToken] = useState(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [loading, setLoading] = useState(false);

  // Configuration - client_id should be stored securely
  const clientId = 'your-client-id';
  const redirectUri = 'your-redirect-uri';
  const tokenEndpoint = 'https://your-oauth-server.com/token';
  const authorizationEndpoint = 'https://your-oauth-server.com/authorize';

  // Secure storage functions
  const storeToken = async (key, value) => {
    await SecureStore.setItemAsync(key, value);
  };

  const getToken = async (key) => {
    return await SecureStore.getItemAsync(key);
  };

  const removeToken = async (key) => {
    await SecureStore.deleteItemAsync(key);
  };

  // Validate URL and redirect URI
  const validateUrl = (url) => {
    try {
      const parsed = new URL(url);
      return parsed.protocol === 'https:';
    } catch (error) {
      return false;
    }
  };

  // Exchange authorization code for tokens
  const exchangeCodeForTokens = async (code) => {
    try {
      const response = await fetch(tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
          'Authorization': `Basic ${btoa(`${clientId}:`)}`,
        },
        body: new URLSearchParams({
          grant_type: 'authorization_code',
          code: code,
          redirect_uri: redirectUri,
        }),
      });

      const data = await response.json();
      
      if (response.ok) {
        await storeToken('access_token', data.access_token);
        await storeToken('refresh_token', data.refresh_token);
        setAccessToken(data.access_token);
        setRefreshToken(data.refresh_token);
        setIsAuthenticated(true);
        return true;
      } else {
        throw new Error(data.error || 'Token exchange failed');
      }
    } catch (error) {
      console.error('Token exchange error:', error);
      throw error;
    }
  };

  // Refresh access token
  const refreshAccessToken = async () => {
    if (!refreshToken) return null;

    try {
      const response = await fetch(tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
          'Authorization': `Basic ${btoa(`${clientId}:`)}`,
        },
        body: new URLSearchParams({
          grant_type: 'refresh_token',
          refresh_token: refreshToken,
        }),
      });

      const data = await response.json();
      
      if (response.ok) {
        await storeToken('access_token', data.access_token);
        setAccessToken(data.access_token);
        return data.access_token;
      } else {
        throw new Error(data.error || 'Token refresh failed');
      }
    } catch (error) {
      console.error('Token refresh error:', error);
      setIsAuthenticated(false);
      return null;
    }
  };

  // Handle authentication
  const handleAuth = async () => {
    if (loading) return;
    
    setLoading(true);
    
    try {
      const redirectUrl = redirectUri;
      
      if (!validateUrl(redirectUrl)) {
        throw new Error('Invalid redirect URI');
      }

      const authUrl = `${authorizationEndpoint}?` +
        `response_type=code&` +
        `client_id=${encodeURIComponent(clientId)}&` +
        `redirect_uri=${encodeURIComponent(redirectUrl)}&` +
        `scope=openid profile email`;

      const result = await WebBrowser.openAuthSessionAsync(authUrl, redirectUrl);
      
      if (result.type === 'success' && result.url) {
        const url = new URL(result.url);
        const code = url.searchParams.get('code');
        
        if (code) {
          await exchangeCodeForTokens(code);
        } else {
          throw new Error('Authorization code not found');
        }
      } else {
        throw new Error('Authentication cancelled');
      }
    } catch (error) {
      Alert.alert('Authentication Error', error.message);
      console.error('Auth error:', error);
    } finally {
      setLoading(false);
    }
  };

  // Check for existing tokens on app start
  useEffect(() => {
    const checkTokens = async () => {
      try {
        const storedAccessToken = await getToken('access_token');
        const storedRefreshToken = await getToken('refresh_token');
        
        if (storedAccessToken && storedRefreshToken) {
          setAccessToken(storedAccessToken);
          setRefreshToken(storedRefreshToken);
          setIsAuthenticated(true);
        }
      } catch (error) {
        console.error('Token check error:', error);
      }
    };

    checkTokens();
  }, []);

  // Auto-refresh tokens when needed
  useEffect(() => {
    const refreshInterval = setInterval(async () => {
      if (isAuthenticated && refreshToken) {
        try {
          const currentToken = await getToken('access_token');
          if (currentToken) {
            // Simple check - in production, validate token expiration
            const now = Math.floor(Date.now() / 1000);
            // Token expiration would be in JWT payload or API response
            // For demo, we'll refresh periodically
            await refreshAccessToken();
          }
        } catch (error) {
          console.error('Auto-refresh error:', error);
        }
      }
    }, 300000); // 5 minutes

    return () => clearInterval(refreshInterval);
  }, [isAuthenticated, refreshToken]);

  // Logout function
  const handleLogout = async () => {
    try {
      await removeToken('access_token');
      await removeToken('refresh_token');
      setAccessToken(null);
      setRefreshToken(null);
      setIsAuthenticated(false);
    } catch (error) {
      console.error('Logout error:', error);
    }
  };

  return (
    <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center', padding: 20 }}>
      <Text style={{ fontSize: 24, marginBottom: 20 }}>OAuth Client</Text>
      
      {!isAuthenticated ? (
        <TouchableOpacity 
          onPress={handleAuth}
          disabled={loading}
          style={{ 
            backgroundColor: '#007AFF', 
            padding: 15, 
            borderRadius: 8,
            minWidth: 200,
            alignItems: 'center'
          }}
        >
          <Text style={{ color: 'white', fontWeight: 'bold' }}>
            {loading ? 'Authenticating...' : 'Login with OAuth'}
          </Text>
        </TouchableOpacity>
      ) : (
        <View style={{ alignItems: 'center' }}>
          <Text style={{ marginBottom: 20 }}>Authenticated</Text>
          <TouchableOpacity 
            onPress={handleLogout}
            style={{ 
              backgroundColor: '#FF3B30', 
              padding: 15, 
              borderRadius: 8,
              minWidth: 200,
              alignItems: 'center'
            }}
          >
            <Text style={{ color: 'white', fontWeight: 'bold' }}>Logout</Text>
          </TouchableOpacity>
        </View>
      )}
    </View>
  );
};

export default OAuthClient;